    "factual_error", "unsupported_claim", "tone_mismatch", "missing_citation",
]
GRADER_SCHEMA = {
    type: "object",
    properties: {
        findings: {type: "array", items: {
            type: "object",
            properties: {
                category: {enum: FROZEN_RUBRIC},   # frozen-rubric-reflection
                span:     {type: "string"},
                fix:      {type: "string"},
            },
            required: ["category", "span", "fix"],
        }},
        accepted: {type: "boolean"},
    },
}

function grade_blind_against_frozen(artefact, trace):
    grader_ctx = new_context()                        # isolated from producer ctx

    grader_prompt = render(
        system="Flag only the listed categories. Do not invent new ones.",
        rubric=FROZEN_RUBRIC,
        artefact=artefact,
        # explicitly NOT: producer reasoning, scratchpad, prior turns
    )

    verdict = grader.run(
        grader_ctx,
        grader_prompt,
        response_schema=GRADER_SCHEMA,                # rejects invented categories
        temperature=0.0,
    )

    # The two patterns close the loop together: isolation prevents framing leak,
    # the frozen rubric prevents the grader inventing fresh criteria each run.
    audit_log.append({
        artefact: artefact,
        producer_trace: trace,                         # logged, NOT seen by grader
        verdict: verdict,
        rubric_version: FROZEN_RUBRIC,
    })
    return verdict

# Why this works: isolation stops the grader inheriting the producer's framing;
# the frozen rubric stops the grader inventing fresh criteria. Either alone
# leaks; composed, the grader can only flag known categories about content it
# has only seen from the outside.
# Related: see `frozen-rubric-reflection`, `same-model-self-critique`.

type Commitment = {
    id: str, statement: str, raised_in_turn: str,
    deadline: timestamp | None,
    status: "open" | "followed-through" | "expired",
    evidence: any | None, closed_at: timestamp | None,
}

ledger = append_only_store()

function extract_commitments(turn):
    # Cheap-tier extractor — small model, structured output, runs out-of-band.
    candidates = cheap_llm.generate(
        prompt="List explicit promises as JSON: {statement, deadline_iso_or_null}.",
        input=turn.text,
        response_schema=COMMITMENT_LIST,
    )
    for c in candidates:
        ledger.append(Commitment(
            id=new_id(), statement=c.statement,
            raised_in_turn=turn.id,
            deadline=parse_iso(c.deadline_iso_or_null),
            status="open", evidence=None, closed_at=None,
        ))

function mark_followed_through(commit_id, evidence):
    c = ledger.get(commit_id)
    verdict = judge.score(c.statement, evidence)        # did evidence really discharge it?
    if verdict.failed:
        return Reject(verdict)                          # do not let the agent self-launder
    assert current_turn().id != c.raised_in_turn        # no same-turn self-close
    ledger.update(commit_id, status="followed-through", evidence=evidence,
                  closed_at=now())

function mark_expired(commit_id):
    ledger.update(commit_id, status="expired", closed_at=now())

function check_expirations():
    for c in ledger.where(status="open"):
        if c.deadline and now() > c.deadline:
            mark_expired(c.id)

function surface_open_for_agent():
    return ledger.where(status="open", deadline_within=next_hour())

# Why this works: producing an intent is satisfying enough that the same
# model rounds its own retrospective summary in its favour. A separate
# ledger plus a verifier on close turns 'agent said vs agent did' into an
# auditable gap rather than a private feeling.
# Related: see `decision-log`, `reflection`, `todo-list-driven-agent`.

function variant_eval_on_dimensional_grid(slot, eval_set, rubric):
    # Group eval_set by dimensional tuple — these are the cells we'll judge per.
    by_cell = group_by(eval_set, key=lambda i: i.dimensions)

    # Score each variant per cell.
    per_cell_scores = {}                              # (cell, variant_id) -> [scores]
    for cell, items in by_cell.items():
        for v in slot.variants:
            for item in items:
                output  = llm.generate(prompt=v.source.format(input=item.input))
                verdict = judge.score(item, output, rubric=rubric)
                per_cell_scores.setdefault((cell, v.id), []).append(verdict.score)

    # Per-cell winner table: a variant wins a cell if it beats baseline by margin.
    cell_winners = {}
    for cell in by_cell:
        scores = {v.id: mean(per_cell_scores[(cell, v.id)]) for v in slot.variants}
        cell_winners[cell] = argmax_with_margin(scores, margin=SIG_MARGIN)

    # Feedback seam: a variant must win or tie on EVERY cell, not just average.
    overall_winners = {v.id: 0 for v in slot.variants}
    for cell, winner in cell_winners.items():
        if winner is None:
            continue
        overall_winners[winner] += 1

    safe = [v for v, wins in overall_winners.items()
            if not any(cell_winners[c] not in (v, None) for c in cell_winners)]

    if not safe:
        # No variant Pareto-dominates; do not silently pick the avg winner.
        return Reject("no variant wins or ties on every dimensional cell")
    return safe[0]

# Why this works: aggregate eval hides regressions on subgroups. The dimensional
# grid forces per-cell comparison; requiring a Pareto-win-or-tie blocks the
# 'great on average, broken for power_user x refund x voice' selection failure.
# Related: see `prompt-variant-evaluation`, `eval-harness`.

function evaluator_optimizer(task, MAX_ITERS=4):
    candidate = generator.generate(task)

    for i in 1..MAX_ITERS:
        verdict = evaluator.score(
            task=task,
            candidate=candidate,
            criteria=CRITERIA,
        )
        # verdict = {pass: bool, score: float, feedback: "..."}

        if verdict.pass:
            return candidate, verdict

        # Feedback must be concrete improvement points, not a vague rating.
        candidate = generator.revise(
            task=task,
            previous=candidate,
            feedback=verdict.feedback,
        )

    return candidate, verdict              # budget hit — best-effort

