FINDING_SCHEMA = {
    type: "object",
    properties: {
        findings: {
            type: "array",
            items: {
                type: "object",
                properties: {
                    category: {enum: RUBRIC},      # <-- frozen
                    span: {type: "string"},
                    fix: {type: "string"},
