function review(artefact):
    response = llm.generate(
        prompt=render(RUBRIC, artefact),
        response_schema=FINDING_SCHEMA,
        temperature=0.0,
    )
    # Schema validation rejects any invented category at parse time.
    return validate(response, FINDING_SCHEMA)

RUBRIC = [
    "factual_error", "unsupported_claim", "tone_mismatch", "missing_citation",
]
RUBRIC_VERSION = "rubric-2026-05-7"
RUBRIC_HASH    = sha256(RUBRIC + RUBRIC_VERSION)
REVIEWER_MODEL = "reviewer-v5"
MAX_REPAIRS = 2
REVIEW_RATE = TokenBucket(capacity=60, refill_per_min=20)

FINDING_SCHEMA = {
    type: "object",
    properties: {
        rubric_version: {const: RUBRIC_VERSION},
        findings: {type: "array", items: {
            type: "object",
            properties: {
                category: {enum: RUBRIC},
                span: {type: "string"},
                fix:  {type: "string"},
            },
            required: ["category", "span", "fix"],
        }},
    },
}

function startup_check():
    expected = config.load("rubric_hash")
    if expected != RUBRIC_HASH:
        # Rubric changed; force eval rerun before the new rubric is used in prod.
        raise RubricDrift(expected=expected, got=RUBRIC_HASH)

function review_observed(artefact):
    if not REVIEW_RATE.take(1):
        return Deferred(artefact)

    for attempt in 0..MAX_REPAIRS:
        response = llm.generate(
            prompt=render(RUBRIC, artefact),
            response_schema=FINDING_SCHEMA,
            temperature=0.0,
            model_id=REVIEWER_MODEL,
        )
        try:
            findings = validate(response, FINDING_SCHEMA)
            audit.emit({kind: "frozen_rubric.review",
                        rubric_version: RUBRIC_VERSION,
                        reviewer_model: REVIEWER_MODEL,
                        n_findings: len(findings.findings)})
            return findings
        except SchemaViolation as e:
            if attempt == MAX_REPAIRS:
                escalate_to_human(artefact, raw=response, error=e)
                return Empty()
            # Targeted repair using the schema error.
            response = llm.generate(
                prompt=render_repair(RUBRIC, artefact, error=e),
                response_schema=FINDING_SCHEMA, temperature=0.0,
                model_id=REVIEWER_MODEL,
            )

# Why this works: the rubric hash catches silent rubric edits before they show
# up as 'why did pass rates drop'. The repair-then-escalate loop stops a single
# malformed JSON output from voiding the review entirely; the audit row makes
# the rubric version that produced each verdict replayable.
# Related: see `structured-output`, `deterministic-llm-sandwich`.

RUBRIC = ["factual_error", "unsupported_claim", "tone_mismatch", "missing_citation"]
FINDING_SCHEMA = {
    findings: list_of({
        category: enum(RUBRIC),
        span:     str,    # MUST appear verbatim in the artefact
        fix:      str,
    }),
}

function sandwiched_review(artefact):
    # PRE: deterministic gate — skip review on artefacts too short to review.
    if len(artefact) < MIN_LENGTH:
        return Empty()

    # LLM: frozen-rubric-reflection in the middle.
    response = llm.generate(
        prompt=render(RUBRIC, artefact),
        response_schema=FINDING_SCHEMA,
        temperature=0.0,
    )
    findings = validate(response, FINDING_SCHEMA)

    # POST: deterministic re-validation — every cited span must actually exist
    # in the artefact. A finding that invented its span gets dropped, not shipped.
    verified = []
    dropped  = []
    for f in findings.findings:
        if artefact.contains(f.span):
            verified.append(f)
        else:
            dropped.append(f)
            audit.emit({kind: "sandwich.post.span_not_found",
                        category: f.category, span: f.span})

    if dropped:
        # Feedback seam: drop count is a calibration signal. Many dropped findings
        # over a window means the reviewer is hallucinating citations.
        calibration_log.append({reviewer_drop_rate: len(dropped) / len(findings.findings)})

    return {findings: verified, dropped: dropped}

# Why this works: the frozen rubric stops the reviewer inventing new categories;
# the deterministic post-check stops the reviewer fabricating spans inside the
# allowed categories. Together they catch both shapes of confabulation that a
# reviewer can otherwise produce.
# Related: see `deterministic-llm-sandwich`, `structured-output`.

FEEDBACK_SCHEMA_VERSION = "hf-2026-05-3"
JUDGE_MODEL = "sanity-judge-v2"
REVIEW_SLA = 30min
MAX_ITERS = 4

FEEDBACK_SCHEMA = {
    overall: enum("approve", "revise", "reject"),
    critique_text: str,
    structured: list_of({
        kind: enum("wrong_section", "missing_claim", "tone_off", "factual_error"),
        span: str, suggestion: str | None,
    }),
}

function human_reflection_observed(task):
    draft = agent.generate(task)

    for i in 1..MAX_ITERS:
        review_id = ui.review_queue.submit({
            artefact: draft,
            schema: FEEDBACK_SCHEMA,
            schema_version: FEEDBACK_SCHEMA_VERSION,
            sla: REVIEW_SLA,
            prompt: "Critique, do not just approve. Be concrete.",
        })
        try:
            feedback = ui.review_queue.await(review_id, timeout=REVIEW_SLA)
        except SLATimeout:
            # Reviewer didn't respond in time -> escalate, NEVER auto-approve.
            return escalate_to_owner(draft, reason="reviewer_sla_breach",
                                     reviewer=ui.assigned_reviewer(review_id))

        audit.emit({kind: "human_reflect.feedback", iter: i,
                    overall: feedback.overall,
                    reviewer: feedback.reviewer_id,
                    schema_version: FEEDBACK_SCHEMA_VERSION,
                    judge_model: JUDGE_MODEL,
                    n_findings: len(feedback.structured)})

        if feedback.overall == "approve":
            return draft
        if feedback.overall == "reject":
            return escalate_to_owner(draft, feedback)

        # Sanity-check: a judge model scores whether the feedback is consistent
        # with the draft. Persistently inconsistent feedback per-reviewer is
        # logged as calibration data (not a gate, just visibility).
        sanity = judge.score(draft, against=feedback, model_id=JUDGE_MODEL)
        reviewer_calibration.append({
            reviewer: feedback.reviewer_id, sanity_score: sanity.score,
        })

        draft = agent.revise(
            previous=draft,
            critique=feedback.critique_text,
            structured_findings=feedback.structured,
        )

    return draft

# Why this works: the SLA + escalation prevents a missing reviewer from being
# the silent failure mode (which would let approve-on-timeout creep in). The
# reviewer_calibration log makes 'this reviewer's critiques don't match their
# own drafts' into a queryable signal rather than a vibe.
# Related: see `human-in-the-loop`, `approval-queue`.

function generate_with_prm(question, N=8):
    candidates = []
    for i in 1..N:
        # Each candidate is a sequence of steps, not a single answer.
        steps = llm.generate_cot(question, temperature=0.7, seed=i)
        step_scores = [prm.score(question, steps[:k+1]) for k in 0..len(steps)-1]
        candidates.append({
            steps: steps,
            step_scores: step_scores,
            min_step: min(step_scores),       # weakest link
            final: extract_final(steps),
        })

    # Reject any candidate with a low intermediate step, even if its
    # final answer looks fine — the reasoning is unreliable.
    viable = [c for c in candidates if c.min_step >= MIN_STEP_THRESHOLD]
    if not viable:
        return abstain("no viable trace")

    return max(viable, key=lambda c: mean(c.step_scores)).final

function adaptive_variant_eval(slot, eval_set, rubric, SAMPLE_BUDGET=600):
    # bayesian-bandit-experimentation: each variant is an arm with a Beta
    # posterior over its pass-rate; we update from per-item evals.
    bandit = {v.id: BetaPosterior(alpha=1, beta=1) for v in slot.variants}

    while SAMPLE_BUDGET > 0 and len(bandit) > 1:
        # Thompson-sample to pick which variant to evaluate next.
        sampled_rates = {vid: post.sample() for vid, post in bandit.items()}
        chosen_variant = argmax(sampled_rates)
        item = eval_set.next_unused(chosen_variant)
        if item is None:
            del bandit[chosen_variant]                  # exhausted this arm
            continue

        v = slot.variant_by_id(chosen_variant)
        output  = llm.generate(prompt=v.source.format(input=item.input))
        verdict = judge.score(item, output, rubric=rubric)

        # Update posterior.
        if verdict.passed:
            bandit[chosen_variant].alpha += 1
        else:
            bandit[chosen_variant].beta += 1
        SAMPLE_BUDGET -= 1

        # Feedback seam: prune variants whose 95% upper bound is below the
        # current best lower bound. They cannot catch up.
        best_lower = max(post.lower_95() for post in bandit.values())
        for vid in list(bandit):
            if bandit[vid].upper_95() < best_lower:
                audit.emit({kind: "variant_eval.pruned",
                            variant: vid, posterior: bandit[vid]})
                del bandit[vid]

    if not bandit:
        return Reject("all variants pruned")
    return argmax({vid: post.mean() for vid, post in bandit.items()})

# Why this works: running every variant on every item is wasteful when the
# weak variants are obviously weak by item 50. The bandit spends sample budget
# where it changes the answer — the posterior is the explicit gate, so audit
# can show which variants were pruned with which evidence.
# Related: see `bayesian-bandit-experimentation`, `eval-harness`.

function reflect(task, MAX_ITERS=3):
    draft = llm.generate(task)

    for i in 1..MAX_ITERS:
        critique = llm.generate(
            prompt=critic_persona_prompt(task, draft),
            # critic_persona: 'You are a senior reviewer. List concrete issues.'
        )

        if critique.says_no_issues():
            return draft

        draft = llm.generate(
            prompt=revise_prompt(task, draft, critique),
        )

    return draft

function self_consistency(prompt, N=8, temperature=0.7):
    samples = []
    for i in 1..N:
        out = llm.generate(prompt, temperature=temperature, seed=i)
        samples.append(extract_answer(out))

    if answer_type == "discrete":
        answer, count = majority_vote(samples)
        confidence = count / N
    elif answer_type == "numeric":
        answer = median(samples)
        confidence = 1.0 - normalized_iqr(samples)
    else:
        answer = judge.pick_best(prompt, samples)
        confidence = judge.agreement_score(samples)

    log("self_consistency_variance", variance(samples))
    return {answer: answer, confidence: confidence, n: N}

function self_consistency_then_debate(prompt, N=8):
    samples = [extract_answer(llm.generate(prompt, temperature=0.7, seed=i))
               for i in 1..N]

    answer, count = majority_vote(samples)
    confidence = count / N

    if confidence >= 0.6:
        return {answer: answer, confidence: confidence}

    # Ambiguous -> compose with `debate`. Pick top two candidate answers and
    # have two debater roles argue for each before a judge.
    top_two = top_k_candidates(samples, k=2)
    if len(top_two) < 2:
        return abstain("insufficient distinct candidates")

    transcript = []
    for round_idx in 1..3:
        for stance in top_two:
            argument = llm.generate(
                prompt=render(
                    "Argue for this answer: {stance}\nPrevious arguments: {prev}",
                    stance=stance, prev=transcript,
                ),
            )
            transcript.append({stance: stance, round: round_idx, argument: argument})

    # Feedback seam: a separate judge model picks based on the debate, not on
    # the original sample vote alone.
    judge_verdict = judge.score(
        prompt=prompt,
        candidates=top_two,
        debate_transcript=transcript,
    )

    return {
        answer: judge_verdict.winner,
        confidence: judge_verdict.confidence,
        method: "self_consistency_then_debate",
    }

# Why this works: self-consistency tells you the modal answer but not which
# answer is right when the modal share is weak. Debate forces each candidate's
# best argument into the open; the judge then has structured grounds to pick,
# not just a vote count.
# Related: see `debate`, `confidence-reporting`.

function self_refine(task, MAX_ITERS=4):
    output = llm.generate(generate_prompt(task))

    for i in 1..MAX_ITERS:
        # SAME model, feedback role.
        feedback = llm.generate(feedback_prompt(task, output))

        if feedback.says_no_more_issues():
            return output

        # SAME model, refine role.
        output = llm.generate(refine_prompt(task, output, feedback))

    return output

