# Register the world model as just another tool.
world_model_tool = Tool(
    name="simulate",
    description="Roll out a candidate action sequence from the current state.",
    schema={
        state: STATE_SCHEMA,
        actions: list_of(ACTION_SCHEMA),
        horizon: int,
    },
    invoke=lambda args: world_model.rollout(**args),  # returns frames + uncertainty
)

function plan_with_simulation(goal, candidate_action_sequences):
    rollouts = []
    for actions in candidate_action_sequences:
        rollout = world_model_tool.invoke({
            state: perceive_current(),
            actions: actions,
            horizon: H,
        })
        rollouts.append({
            actions: actions,
            predicted: rollout.frames,
            uncertainty: rollout.uncertainty,
        })

    # Agent compares text-level reasoning against simulator predictions.
    chosen = agent.pick(goal, rollouts)

    # Gate irreversible / expensive actions on simulator agreement.
    if chosen.actions.is_irreversible() and chosen.uncertainty > GATE:
        return abstain("world model uncertain on irreversible action")
    return chosen.actions

function tot_with_world_model(goal, BRANCH_FACTOR=3, MAX_DEPTH=4):
    root = ThoughtNode(state=perceive_current(), partial_plan=[])
    frontier = [root]

    for depth in 1..MAX_DEPTH:
        children = []
        for node in frontier:
            # tree-of-thoughts: generate candidate next-step thoughts.
            candidate_steps = llm.generate_candidate_steps(
                goal=goal, current=node, k=BRANCH_FACTOR,
            )

            for step in candidate_steps:
                # world-model-as-tool: SIMULATE the new partial plan to get
                # a grounded value estimate, instead of letting the LLM
                # self-rate the branch.
                rollout = world_model_tool.invoke({
                    state: node.state,
                    actions: [step], horizon: 1,
                })
                value = score_against_goal(rollout.predicted_state, goal)

                child = ThoughtNode(
                    state=rollout.predicted_state,
                    partial_plan=node.partial_plan + [step],
                    value=value, uncertainty=rollout.uncertainty,
                    parent=node,
                )
                children.append(child)

        # Feedback seam: prune by simulator-grounded value AND uncertainty,
        # not by text-level plausibility.
        frontier = sorted(children,
                          key=lambda c: (-c.value, c.uncertainty))[:BRANCH_FACTOR]

        if any(is_goal_reached(c.state, goal) for c in frontier):
            return reconstruct_plan(first_goal_node(frontier))

    # Best partial plan found.
    best = max(frontier, key=lambda c: c.value)
    if best.uncertainty > UNCERTAINTY_GATE:
        return abstain(reason="best_branch_uncertain")
    return reconstruct_plan(best)

# Why this works: ToT's classic weakness is that the LLM that generates
# branches also self-rates them, so the model's biases propagate end-to-end.
# Using a world-model rollout for the value head decouples generation from
# evaluation and makes pruning rest on grounded predictions, not on
# self-assessment.
# Related: see `tree-of-thoughts`, `simulate-before-actuate`.

# 1. the model produces an answer that may cite external authorities
answer = llm.generate(messages=conversation)

# 2. parse structured citations out of the finished text
citations = extract_citations(answer)   # -> [{kind, name, docket, jurisdiction, title, doi}, ...]

kept, stripped = [], []
for c in citations:
    # 3. resolve against an EXTERNAL ground-truth registry (not the retrieval set)
    if c.kind in ("case", "statute"):
        record = legal_registry.resolve(c)      # Westlaw / CourtListener / LexisNexis
    else:
        record = biblio_registry.resolve(c)     # PubMed / DOI resolver

    # 4. require an exact match on the load-bearing fields
    if record and record.matches(c, fields=["docket", "jurisdiction", "title"]):
        c.resolved = record                      # keep + annotate
        kept.append(c)
    else:
        stripped.append(c)                       # fabricated / repealed / wrong jurisdiction

# 5. disposition: strip non-resolving citations; block in the strictest mode
if stripped and policy == "block":
    return regenerate_or_escalate(answer, stripped)
answer = redact_citations(answer, stripped)      # remove unverified authorities from the text
answer = annotate_citations(answer, kept)        # attach resolved records / links
return answer, flags(stripped)                   # surface what was removed
